CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Спина - Тяги верхнего блока узким хватом', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-uzkim-khvatom', 'Это превосходное упражнение для полного развития широчайшей мышцы спины и большой круглой мышцы. При сведении лопаток задействуются ромбовидная и трапециевидная мышцы, а также задние части дельтовидной мышцы.', 'Спина - Тяги верхнего блока узким хватом', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-uzkim-khvatom', 'Это превосходное упражнение для полного развития широчайшей мышцы спины и большой круглой мышцы. При сведении лопаток задействуются ромбовидная и трапециевидная мышцы, а также задние части дельтовидной мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Спина - Тяги верхнего блока прямыми руками', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-pryamymi-rukami', 'Это упражнение также задействует широчайшие и круглые мышцы спины. Пловцы часто используют это упражнение как силовое, позволяющее им получать хорошие результаты в стиле кроль.', 'Спина - Тяги верхнего блока прямыми руками', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-pryamymi-rukami', 'Это упражнение также задействует широчайшие и круглые мышцы спины. Пловцы часто используют это упражнение как силовое, позволяющее им получать хорошие результаты в стиле кроль.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Спина - Тяги нижнего блока (гребля)', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-nizhnego-bloka-greblya', 'Это упражнение превосходно формирует толщину спины, задействуя широчайшую мышцу спины, большую круглую мышцу, задние части дельтовидных мышц.', 'Спина - Тяги нижнего блока (гребля)', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-nizhnego-bloka-greblya', 'Это упражнение превосходно формирует толщину спины, задействуя широчайшую мышцу спины, большую круглую мышцу, задние части дельтовидных мышц.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Спина - Тяги гантели одной рукой', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-ganteli-odnoj-rukoj', 'Это упражнение преимущественно нагружает широчайшие мышцы спины, большую круглую мышцу, заднюю часть дельтовидных мышц, а также трапециевидную и ромбовидную мышцы в конечной фазе движения.', 'Спина - Тяги гантели одной рукой', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-ganteli-odnoj-rukoj', 'Это упражнение преимущественно нагружает широчайшие мышцы спины, большую круглую мышцу, заднюю часть дельтовидных мышц, а также трапециевидную и ромбовидную мышцы в конечной фазе движения.')"
