CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Жим штанги, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-naklonnoj-skame', 'Это упражнение задействует ключичный отдел большой грудной мышцы, передние части дельтовидных мышц, трицепсы, переднюю зубчатую и малую грудную мышцы.', 'Грудь - Жим штанги, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-naklonnoj-skame', 'Это упражнение задействует ключичный отдел большой грудной мышцы, передние части дельтовидных мышц, трицепсы, переднюю зубчатую и малую грудную мышцы.')"
