CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Разведение гантелей, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/razvedenie-gantelej-lezha-na-naklonnoj-skame', 'Это упражнение локализует усилие главным образом на верхние части большой грудной мышцы. Наряду с протяжкой гантели или штанги (pull-over) это упражнение является базовым для увеличения грудной клетки.', 'Грудь - Разведение гантелей, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/razvedenie-gantelej-lezha-na-naklonnoj-skame', 'Это упражнение локализует усилие главным образом на верхние части большой грудной мышцы. Наряду с протяжкой гантели или штанги (pull-over) это упражнение является базовым для увеличения грудной клетки.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Жим штанги, лежа на горизонтальной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-gorizontalnoj-skame', 'Это упражнение развивает всю большую грудную мышцу, малую грудную мышцу, трицепсы, переднюю часть дельтовидной мышцы, зубчатые и клювовидно-плечевые мышцы.', 'Грудь - Жим штанги, лежа на горизонтальной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-gorizontalnoj-skame', 'Это упражнение развивает всю большую грудную мышцу, малую грудную мышцу, трицепсы, переднюю часть дельтовидной мышцы, зубчатые и клювовидно-плечевые мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Отжимания от пола', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/otzhimaniya-ot-pola', 'В положении лицом вниз, упираясь прямыми руками в пол, ладони на ширине плеч или чуть шире. Ноги вместе или слегка расставлены.', 'Грудь - Отжимания от пола', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/otzhimaniya-ot-pola', 'В положении лицом вниз, упираясь прямыми руками в пол, ладони на ширине плеч или чуть шире. Ноги вместе или слегка расставлены.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Жим гантелей лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-gantelej-lezha', 'Это упражнение аналогично жиму штанги лежа, за исключением того, что упражнение с гантелями характеризуется большей амплитудой, способствующей лучшему растягиванию больших грудных мышц.', 'Грудь - Жим гантелей лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-gantelej-lezha', 'Это упражнение аналогично жиму штанги лежа, за исключением того, что упражнение с гантелями характеризуется большей амплитудой, способствующей лучшему растягиванию больших грудных мышц.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Разведение гантелей лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/razvedenie-gantelej-lezha', 'Это базовое упражнение для увеличения объема груди и способствует увеличению объема легких. Кроме того, оно придает эластичность мышцам.', 'Грудь - Разведение гантелей лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/razvedenie-gantelej-lezha', 'Это базовое упражнение для увеличения объема груди и способствует увеличению объема легких. Кроме того, оно придает эластичность мышцам.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Тяга штанги лежа PULL-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/tyaga-shtangi-lezha-pull-over', 'Упражнение великолепно расширяет грудную клетку. Выполняя его, используйте нагрузки с легким весом и следите за положением туловища и правильным дыханием.', 'Грудь - Тяга штанги лежа PULL-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/tyaga-shtangi-lezha-pull-over', 'Упражнение великолепно расширяет грудную клетку. Выполняя его, используйте нагрузки с легким весом и следите за положением туловища и правильным дыханием.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Жим штанги, лежа на скамье с уклоном', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-skame-s-uklonom', 'Это упражнение формирует нижний подрез грудных мышц. Кроме того, при опускании грифа штанги к шее растягивается большая грудная мышца, что способствует увеличению ее эластичности.', 'Грудь - Жим штанги, лежа на скамье с уклоном', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-skame-s-uklonom', 'Это упражнение формирует нижний подрез грудных мышц. Кроме того, при опускании грифа штанги к шее растягивается большая грудная мышца, что способствует увеличению ее эластичности.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Отжимания на брусьях', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/otzhimaniya-na-brusyakh', 'Это упражнение прекрасно растягивает большие грудные мышцы и повышает эластичность мышц плечевого пояса.', 'Грудь - Отжимания на брусьях', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/otzhimaniya-na-brusyakh', 'Это упражнение прекрасно растягивает большие грудные мышцы и повышает эластичность мышц плечевого пояса.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Жим штанги узким хватом, лежа на скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-uzkim-khvatom-lezha-na-skame', 'Это упражнение великолепно подходит для развития внутренней прорисовки грудной мышцы и трицепсов.', 'Грудь - Жим штанги узким хватом, лежа на скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-uzkim-khvatom-lezha-na-skame', 'Это упражнение великолепно подходит для развития внутренней прорисовки грудной мышцы и трицепсов.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Сведение рук на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/svedenie-ruk-na-trenazhere', 'Это упражнение разрабатывает большие грудные мышцы. Во время сведения локтей оно локализует усилие на уровне внутренней части мышц груди, также разрабатывая клювовидно-плечевые мышцы и короткую головку бицепсов.', 'Грудь - Сведение рук на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/svedenie-ruk-na-trenazhere', 'Это упражнение разрабатывает большие грудные мышцы. Во время сведения локтей оно локализует усилие на уровне внутренней части мышц груди, также разрабатывая клювовидно-плечевые мышцы и короткую головку бицепсов.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Сведение верхних блоков CROSS-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/svedenie-verkhnikh-blokov-cross-over', 'Это упражнение превосходно развивает большую грудную мышцу. Меняя угол наклона туловища и траекторию движения рук, то есть, сближая руки на различном по высоте уровне можно задействовать все части большой грудной мышцы.', 'Грудь - Сведение верхних блоков CROSS-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/svedenie-verkhnikh-blokov-cross-over', 'Это упражнение превосходно развивает большую грудную мышцу. Меняя угол наклона туловища и траекторию движения рук, то есть, сближая руки на различном по высоте уровне можно задействовать все части большой грудной мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Грудь - Тяга гантели из-за головы лежа PULL-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/tyaga-ganteli-iz-za-golovy-lezha-pull-over', 'Это упражнение развивает внутреннюю часть большой грудной мышцы, длинную головку трицепсов, большую круглую мышцу, широчайшую мышцу спины, а также переднюю зубчатую, ромбовидную и малую грудную мышцы.', 'Грудь - Тяга гантели из-за головы лежа PULL-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/tyaga-ganteli-iz-za-golovy-lezha-pull-over', 'Это упражнение развивает внутреннюю часть большой грудной мышцы, длинную головку трицепсов, большую круглую мышцу, широчайшую мышцу спины, а также переднюю зубчатую, ромбовидную и малую грудную мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Бицепс - Попеременные сгибания рук с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/poperemennye-sgibaniya-ruk-s-gantelyami', 'В упражнении участвуют мышцы: плечелучевая, плечевая, двуглавая (бицепс), передняя дельтовидная, в меньшей степени клювовидно-плечевая и верхний отдел большой грудной мышцы.', 'Бицепс - Попеременные сгибания рук с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/poperemennye-sgibaniya-ruk-s-gantelyami', 'В упражнении участвуют мышцы: плечелучевая, плечевая, двуглавая (бицепс), передняя дельтовидная, в меньшей степени клювовидно-плечевая и верхний отдел большой грудной мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Бицепс - Концентрированное сгибание одной руки с гантелью', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/kontsentrirovannoe-sgibanie-odnoj-ruki-s-gantelyu', 'Это упражнение позволит вам контролировать амплитуду, скорость и размерность движений. Оно предназначено главным образом для работы бицепсов и плечевых мышц.', 'Бицепс - Концентрированное сгибание одной руки с гантелью', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/kontsentrirovannoe-sgibanie-odnoj-ruki-s-gantelyu', 'Это упражнение позволит вам контролировать амплитуду, скорость и размерность движений. Оно предназначено главным образом для работы бицепсов и плечевых мышц.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Бицепс - Сгибание рук с гантелями хватом молоток', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-gantelyami-khvatom-molotok', 'Это лучшее упражнение для плечелучевых мышц. В нем также участвуют бицепс и частично плечевая мышца и в меньшей степени короткий и длинный лучевые разгибатели запястья.', 'Бицепс - Сгибание рук с гантелями хватом молоток', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-gantelyami-khvatom-molotok', 'Это лучшее упражнение для плечелучевых мышц. В нем также участвуют бицепс и частично плечевая мышца и в меньшей степени короткий и длинный лучевые разгибатели запястья.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Бицепс - Сгибание одной руки с рукояткой нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-odnoj-ruki-s-rukoyatkoj-nizhnego-bloka', 'Это хорошее упражнение для изолированной накачки бицепсов.', 'Бицепс - Сгибание одной руки с рукояткой нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-odnoj-ruki-s-rukoyatkoj-nizhnego-bloka', 'Это хорошее упражнение для изолированной накачки бицепсов.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Бицепс - Сгибание рук с рукоятками верхних блоков', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-rukoyatkami-verkhnikh-blokov', 'Это упражнение используют для завершения тренировки по развитию бицепсов. Оно в основном задействует короткую головку, хорошо ее сокращая и растягивая. Это упражнение также тренирует плечевые мышцы и моносуставной разгибатель локтя.', 'Бицепс - Сгибание рук с рукоятками верхних блоков', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-rukoyatkami-verkhnikh-blokov', 'Это упражнение используют для завершения тренировки по развитию бицепсов. Оно в основном задействует короткую головку, хорошо ее сокращая и растягивая. Это упражнение также тренирует плечевые мышцы и моносуставной разгибатель локтя.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Бицепс - Сгибание рук с грифом штанги', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-grifom-shtangi', 'Это упражнение задействует бицепсы, плечевые мышцы и в меньшей степени плечелучевые мышцы, круглые пронаторы, все сгибатели кисти и пальцев. Во избежание отклонения туловища напрягите мышцы ягодиц, живота и спины.', 'Бицепс - Сгибание рук с грифом штанги', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-grifom-shtangi', 'Это упражнение задействует бицепсы, плечевые мышцы и в меньшей степени плечелучевые мышцы, круглые пронаторы, все сгибатели кисти и пальцев. Во избежание отклонения туловища напрягите мышцы ягодиц, живота и спины.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Бицепс - Сгибание рук на тренажере LARRY-SCOTT', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-na-trenazhere-larry-scott', 'Это одно из лучших упражнений для изолированной проработки бицепсов. Оно тренирует также плечевые мышцы и в меньшей степени плечелучевые мышцы и круглые пронаторы.', 'Бицепс - Сгибание рук на тренажере LARRY-SCOTT', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-na-trenazhere-larry-scott', 'Это одно из лучших упражнений для изолированной проработки бицепсов. Оно тренирует также плечевые мышцы и в меньшей степени плечелучевые мышцы и круглые пронаторы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Бицепс - Сгибание рук на скамье LARRY-SCOTT', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-na-skame-larry-scott', 'Это одно из лучших упражнений для локального воздействия на бицепсы.', 'Бицепс - Сгибание рук на скамье LARRY-SCOTT', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-na-skame-larry-scott', 'Это одно из лучших упражнений для локального воздействия на бицепсы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Предплечье - Сгибание рук со штангой хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-so-shtangoj-khvatom-sverkhu', 'Это упражнение прорабатывает мышцы - разгибатели запястья, длинный лучевой разгибатель запястья, короткий лучевой разгибатель запястья, разгибатель пальцев, разгибатель мизинца и локтевой разгибатель запястья.', 'Предплечье - Сгибание рук со штангой хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-so-shtangoj-khvatom-sverkhu', 'Это упражнение прорабатывает мышцы - разгибатели запястья, длинный лучевой разгибатель запястья, короткий лучевой разгибатель запястья, разгибатель пальцев, разгибатель мизинца и локтевой разгибатель запястья.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Предплечье - Разгибание запястий со штангой хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-zapyastij-so-shtangoj-khvatom-sverkhu', 'Это упражнение укрепляет суставы запястья, которые часто бывают слабыми из-за недостаточной силы мышц разгибателей кисти.', 'Предплечье - Разгибание запястий со штангой хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-zapyastij-so-shtangoj-khvatom-sverkhu', 'Это упражнение укрепляет суставы запястья, которые часто бывают слабыми из-за недостаточной силы мышц разгибателей кисти.')"
