CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Приседания со штангой на груди', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-so-shtangoj-na-grudi', 'Этот прием во время приседаний локализует больше нагрузки на четырехглавые мышцы, чем при классических приседаниях. Совершая полную амплитуду, вы вовлекаете в работу ягодичные мышцы.', 'Ноги - Приседания со штангой на груди', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-so-shtangoj-na-grudi', 'Этот прием во время приседаний локализует больше нагрузки на четырехглавые мышцы, чем при классических приседаниях. Совершая полную амплитуду, вы вовлекаете в работу ягодичные мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Приседания со штангой на плечах', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-so-shtangoj-na-plechakh', 'Приседания разрабатывают главным образом четырехглавые мышцы, ягодичные мышцы, все приводящие мышцы, мышцы, выпрямляющие позвоночник, мышцы живота, а также седалищно-большеберцовые мышцы.', 'Ноги - Приседания со штангой на плечах', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-so-shtangoj-na-plechakh', 'Приседания разрабатывают главным образом четырехглавые мышцы, ягодичные мышцы, все приводящие мышцы, мышцы, выпрямляющие позвоночник, мышцы живота, а также седалищно-большеберцовые мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Широкие приседания', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/shirokie-prisedaniya', 'Особенностью упражнения являются очень широко расставленные ноги с разведенными в стороны носками. Это дополнительно включает в работу внутренние мышцы бедра.', 'Ноги - Широкие приседания', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/shirokie-prisedaniya', 'Особенностью упражнения являются очень широко расставленные ноги с разведенными в стороны носками. Это дополнительно включает в работу внутренние мышцы бедра.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Наклонный жим ногами', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/naklonnyj-zhim-nogami', 'Это упражнение можно выполнять людям, которые страдают от болей в спине и поэтому не могут делать приседания. Тем не менее, обязательно прижимайте ягодицы к спинке тренажера.', 'Ноги - Наклонный жим ногами', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/naklonnyj-zhim-nogami', 'Это упражнение можно выполнять людям, которые страдают от болей в спине и поэтому не могут делать приседания. Тем не менее, обязательно прижимайте ягодицы к спинке тренажера.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Приседания на тренажере НАСК SQUAT', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-na-trenazhere-nask-squat', 'Это движение создает основную нагрузку на четырехглавые мышцы бедер. Если ступни выставить вперед, то основная нагрузка перейдет на мышцы ягодиц.', 'Ноги - Приседания на тренажере НАСК SQUAT', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-na-trenazhere-nask-squat', 'Это движение создает основную нагрузку на четырехглавые мышцы бедер. Если ступни выставить вперед, то основная нагрузка перейдет на мышцы ягодиц.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Разгибание ног', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-nog', 'Это движение лучше всего подходит для изолированной нагрузки на четырехглавые мышцы. Это упражнение обычно рекомендуют начинающим.', 'Ноги - Разгибание ног', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-nog', 'Это движение лучше всего подходит для изолированной нагрузки на четырехглавые мышцы. Это упражнение обычно рекомендуют начинающим.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Мертвые тяги в стиле сумо', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-v-stile-sumo', 'В отличие от обычного классического подъема штанги от пола, в этом упражнении более интенсивно работают четырехглавая мышца бедра и приводящая мышца бедра и в меньшей степени - мышцы спины.', 'Ноги - Мертвые тяги в стиле сумо', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-v-stile-sumo', 'В отличие от обычного классического подъема штанги от пола, в этом упражнении более интенсивно работают четырехглавая мышца бедра и приводящая мышца бедра и в меньшей степени - мышцы спины.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Сгибание ног лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-nog-lezha', 'Это упражнение вовлекает в работу всю группу седалищно-подколенных мышц бедер(бицепсы бедра), икроножные мышцы, а также более глубоко расположенные подколенные мышцы.', 'Ноги - Сгибание ног лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-nog-lezha', 'Это упражнение вовлекает в работу всю группу седалищно-подколенных мышц бедер(бицепсы бедра), икроножные мышцы, а также более глубоко расположенные подколенные мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Сгибание одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-odnoj-nogi-stoya', 'Это упражнение вовлекает в работу все седалищно-подколенные мышцы бедра (полусухожильные, полуперепончатые, бицепсы бедра - короткие и длинные головки) и в меньшей мере икроножные мышцы.', 'Ноги - Сгибание одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-odnoj-nogi-stoya', 'Это упражнение вовлекает в работу все седалищно-подколенные мышцы бедра (полусухожильные, полуперепончатые, бицепсы бедра - короткие и длинные головки) и в меньшей мере икроножные мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Сгибание ног сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-nog-sidya', 'Это упражнение задействует все седалищно-подколенные мышцы бедра, а также в меньшей степени икроножные мышцы.', 'Ноги - Сгибание ног сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-nog-sidya', 'Это упражнение задействует все седалищно-подколенные мышцы бедра, а также в меньшей степени икроножные мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Подъемы торса с добрым утром', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-torsa-s-dobrym-utrom', 'Это упражнение, разрабатывающее большую ягодичную мышцу и мышцы спины, оказывает благоприятное воздействие на седалищно-подколенные мышцы.', 'Ноги - Подъемы торса `с добрым утром`', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-torsa-s-dobrym-utrom', 'Это упражнение, разрабатывающее большую ягодичную мышцу и мышцы спины, оказывает благоприятное воздействие на седалищно-подколенные мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Мертвые тяги со штангой, ноги прямые', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-so-shtangoj-nogi-pryamye', 'Движения упражнения активно включают в работу большую ягодичную и седалищно-большеберцовую мышцу. Также хорошо задействованы мышцы, выпрямляющие позвоночник.', 'Ноги - Мертвые тяги со штангой, ноги прямые', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-so-shtangoj-nogi-pryamye', 'Движения упражнения активно включают в работу большую ягодичную и седалищно-большеберцовую мышцу. Также хорошо задействованы мышцы, выпрямляющие позвоночник.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Поясничные прогибания с прямой спиной', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/poyasnichnye-progibaniya-2', 'Упражнение отлично подходит для прокачки задней поверхности бедра и ягодичных мышц. Мышцы, выпрямляющие позвоночник почти не работают за счет прямой спины.', 'Ноги - Поясничные прогибания с прямой спиной', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/poyasnichnye-progibaniya-2', 'Упражнение отлично подходит для прокачки задней поверхности бедра и ягодичных мышц. Мышцы, выпрямляющие позвоночник почти не работают за счет прямой спины.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Приведение одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/privedenie-odnoj-nogi-stoya', 'Это упражнение задействует приводящие мышцы бедра. Оно великолепно формирует внутреннюю поверхность бедра при регулярном его применении.', 'Ноги - Приведение одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/privedenie-odnoj-nogi-stoya', 'Это упражнение задействует приводящие мышцы бедра. Оно великолепно формирует внутреннюю поверхность бедра при регулярном его применении.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Сведение ног сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/svedenie-nog-sidya', 'Это упражнение тренирует приводящие мышцы. Здесь можно использовать более значительный вес отягощения, чем в упражнении с приведением нижнего блока, хотя и с более ограниченным диапазоном движения.', 'Ноги - Сведение ног сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/svedenie-nog-sidya', 'Это упражнение тренирует приводящие мышцы. Здесь можно использовать более значительный вес отягощения, чем в упражнении с приведением нижнего блока, хотя и с более ограниченным диапазоном движения.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Подъемы на носки стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-na-noski-stoya', 'Это упражнение тренирует трехглавые мышцы голени. Чтобы правильно напрягать эти мышцы, очень важно подниматься на носках как можно выше в каждом повторении движения.', 'Ноги - Подъемы на носки стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-na-noski-stoya', 'Это упражнение тренирует трехглавые мышцы голени. Чтобы правильно напрягать эти мышцы, очень важно подниматься на носках как можно выше в каждом повторении движения.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Подъем на носок одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-em-na-nosok-odnoj-nogi-stoya', 'Это упражнение задействует трицепс голени. Для лучшего результата выполняйте упражнение до появления чувства жжения.', 'Ноги - Подъем на носок одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-em-na-nosok-odnoj-nogi-stoya', 'Это упражнение задействует трицепс голени. Для лучшего результата выполняйте упражнение до появления чувства жжения.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Подъемы на носки в наклоне ослик', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-na-noski-v-naklone-oslik', 'Это - хорошее упражнение для тщательной проработки. Оно задействует трицепс голени и, в частности, икроножные мышцы.', 'Ноги - Подъемы на носки в наклоне ослик', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-na-noski-v-naklone-oslik', 'Это - хорошее упражнение для тщательной проработки. Оно задействует трицепс голени и, в частности, икроножные мышцы.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Жимы стопами на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/zhimy-stopami-na-trenazhere', 'Это упражнение отлично нагружает икроножные и камбаловидные мышцы голени, за счет чего икра выглядит гораздо объемнее, если смотреть на нее сзади.', 'Ноги - Жимы стопами на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/zhimy-stopami-na-trenazhere', 'Это упражнение отлично нагружает икроножные и камбаловидные мышцы голени, за счет чего икра выглядит гораздо объемнее, если смотреть на нее сзади.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Разгибание голени сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-goleni-sidya', 'Это упражнение задействует преимущественно камбаловидные мышцы. Основная функция камбаловидной мышиы состоит в разгибании голени.', 'Ноги - Разгибание голени сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-goleni-sidya', 'Это упражнение задействует преимущественно камбаловидные мышцы. Основная функция камбаловидной мышиы состоит в разгибании голени.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Разгибание голени сидя, со штангой на коленях', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-goleni-sidya-so-shtangoj-na-kolenyakh', 'В отличие от проработки камбаловидных мышц на тренажере этот вид упражнения не позволяет использовать тяжелый вес, так как потребует чрезмерных усилий.', 'Ноги - Разгибание голени сидя, со штангой на коленях', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-goleni-sidya-so-shtangoj-na-kolenyakh', 'В отличие от проработки камбаловидных мышц на тренажере этот вид упражнения не позволяет использовать тяжелый вес, так как потребует чрезмерных усилий.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ноги - Подъемы носков голени сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-noskov', 'Это упражнение формирует мышцы передней части голени, делает их более выносливыми и сильными.', 'Ноги - Подъемы носков голени сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-noskov', 'Это упражнение формирует мышцы передней части голени, делает их более выносливыми и сильными.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Спина - Подъемы с добрым утром сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-s-dobrym-utrom-sidya', 'Это упражнения отлично подойдет для изолированной проработки мышц поясницы и глубоких мышц спины. В отличие, от выполнения подъемов стоя, данный способ исключает нагрузку на ноги и ягодицы.', 'Спина - Подъемы с добрым утром сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-s-dobrym-utrom-sidya', 'Это упражнения отлично подойдет для изолированной проработки мышц поясницы и глубоких мышц спины. В отличие, от выполнения подъемов стоя, данный способ исключает нагрузку на ноги и ягодицы.')"
