CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Спина - Мертвые тяги со штангой, ноги прямые', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-so-shtangoj-nogi-pryamye', 'Движения упражнения активно включают в работу большую ягодичную и седалищно-большеберцовую мышцу. Также хорошо задействованы мышцы, выпрямляющие позвоночник.', 'Спина - Мертвые тяги со штангой, ноги прямые', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-so-shtangoj-nogi-pryamye', 'Движения упражнения активно включают в работу большую ягодичную и седалищно-большеберцовую мышцу. Также хорошо задействованы мышцы, выпрямляющие позвоночник.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ягодицы - Выпады со штангой на плечах', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/vypady-so-shtangoj-na-plechakh', 'Это упражнение в первую очередь задействует большую ягодичную мышцу.', 'Ягодицы - Выпады со штангой на плечах', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/vypady-so-shtangoj-na-plechakh', 'Это упражнение в первую очередь задействует большую ягодичную мышцу.')"
