CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ягодицы - Махи ногой назад с нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-s-nizhnego-bloka', 'Это упражнение вовлекает в работу главным образом большую ягодичную мышцу и в меньшей степени седалищно-большеберцовую мышцу, исключая короткую головку бицепса бедра.', 'Ягодицы - Махи ногой назад с нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-s-nizhnego-bloka', 'Это упражнение вовлекает в работу главным образом большую ягодичную мышцу и в меньшей степени седалищно-большеберцовую мышцу, исключая короткую головку бицепса бедра.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ягодицы - Махи ногой назад с рычагом тренажера', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-s-rychagom-trenazhera', 'Это упражнение задействует главным образом большую ягодичную мышцу, а также в меньшей степени полусухожильную, полуперепончатую мышцы и длинную головку бицепса бедра.', 'Ягодицы - Махи ногой назад с рычагом тренажера', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-s-rychagom-trenazhera', 'Это упражнение задействует главным образом большую ягодичную мышцу, а также в меньшей степени полусухожильную, полуперепончатую мышцы и длинную головку бицепса бедра.')"
CONN.execute "INSERT INTO dictitems (name, url, description, name_ru, url_ru, desc_ru) VALUES ('Ягодицы - Махи ногой назад на полу', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-na-polu', 'Это упражнение, выполняемое прямой ногой, разрабатывает седалищно-подколенные мышцы и большую ягодичную мышцу. При согнутой в колене ноге разрабатывается только большая ягодичная мышца, но менее интенсивно.', 'Ягодицы - Махи ногой назад на полу', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-na-polu', 'Это упражнение, выполняемое прямой ногой, разрабатывает седалищно-подколенные мышцы и большую ягодичную мышцу. При согнутой в колене ноге разрабатывается только большая ягодичная мышца, но менее интенсивно.')"
